+
+/** Run a side effect for a rejected task while preserving that task's rejection. */
+export function tapRejected<T, E>(task: Task<T, E>, fn: (reason: E) => void): Task<T, E>;
+export function tapRejected<T, E>(fn: (reason: E) => void): (task: Task<T, E>) => Task<T, E>;
+export function tapRejected<T, E>(
+  taskOrFn: Task<T, E> | ((reason: E) => void),
+  maybeFn?: (reason: E) => void
+): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
+  if (typeof taskOrFn === 'function') {
+    return (task) => tapRejected(task, taskOrFn);
+  }
+  return taskOrFn.inspectRejected(maybeFn!);
+}
+
+/** Retry a task-producing function up to `n` additional times after rejection. */
+export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
+  const attempts = Math.max(0, Math.floor(n));
+  const attempt = (remaining: number): Task<T, E> =>
+    fn().orElse((reason) => (remaining > 0 ? attempt(remaining - 1) : Task.reject<T, E>(reason)));
+  return attempt(attempts);
+}
